<template>
  <div class="relative pl-16">
    <!-- 时间点 -->
    <div class="absolute left-6 -translate-x-1/2">
      <div class="w-4 h-4 rounded-full" :class="dotColor"></div>
    </div>

    <!-- 内容 -->
    <div class="glass-effect rounded-xl p-6">
      <div class="flex items-center justify-between mb-4">
        <div>
          <span class="text-sm font-semibold px-3 py-1 rounded-full" :class="typeColor">
            {{ item.type === 'work' ? '工作' : item.type === 'education' ? '教育' : '项目' }}
          </span>
          <h3 class="text-xl font-bold mt-2">{{ item.title }}</h3>
          <p class="text-gray-400">{{ item.company }}</p>
        </div>
        <span class="text-2xl font-bold gradient-text">{{ item.year }}</span>
      </div>
      
      <p class="text-gray-300">{{ item.description }}</p>
      
      <!-- 技能标签 -->
      <div class="mt-4 flex flex-wrap gap-2">
        <span class="text-xs px-3 py-1 rounded-full glass-effect">Vue 3</span>
        <span class="text-xs px-3 py-1 rounded-full glass-effect">TypeScript</span>
        <span class="text-xs px-3 py-1 rounded-full glass-effect">性能优化</span>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed } from 'vue'

const props = defineProps<{
  item: {
    year: string
    title: string
    company: string
    description: string
    type: string
  }
}>()

const dotColor = computed(() => {
  const type = props.item.type
  if (type === 'work') return 'bg-blue-500'
  if (type === 'education') return 'bg-green-500'
  return 'bg-purple-500'
})

const typeColor = computed(() => {
  const type = props.item.type
  if (type === 'work') return 'bg-blue-500/20 text-blue-400'
  if (type === 'education') return 'bg-green-500/20 text-green-400'
  return 'bg-purple-500/20 text-purple-400'
})
</script>